// Fold any vision JSON into the extraction item as vision_notes.
const items = $input.all();
const base = items.find(i => i.json.extracted_text) || items[0];
let visionNotes = '';
const v = items.find(i => i.json.candidates || i.json.metric_name);
if (v) {
  try {
    const t = v.json.candidates?.[0]?.content?.parts?.[0]?.text || JSON.stringify(v.json);
    visionNotes = typeof t === 'string' ? t : JSON.stringify(t);
  } catch (e) { visionNotes = ''; }
}
return [{ json: { ...base.json, vision_notes: visionNotes } }];

const j = $input.first().json;
const prompt = `You are HINDSIGHT, a cybersecurity incident-log analyst. Read the SIEM export, vuln scan, or phishing report and return ONLY a valid JSON object matching this schema exactly:
{incident_title, summary, severity (SEV1|SEV2|SEV3|SEV4), incident_type (security|data-incident|vulnerability-scan|malware|phishing|intrusion|ddos|other), status, affected_services[], affected_jurisdictions[], root_cause, trigger, detection_method, entities:{people[],teams[],systems[],dates[],error_codes[]}, action_items:[{action,owner,priority}], contributing_factors[], sentiment, blameless_quality, cvss_score, cve_ids[], confidence_score, metrics:{detected_at,resolved_at,ttd_minutes,ttr_minutes,customer_impact}}
For vuln scans set cvss_score and cve_ids verbatim. When unsure of severity pick the LOWER one.

VISION NOTES (from embedded SIEM/scan charts):
${j.vision_notes || 'none'}

DOCUMENT:
${j.extracted_text}`;
return [{ json: { ...j, prompt } }];

const FENCE = String.fromCharCode(96, 96, 96);
const REQUIRED = ['summary', 'sentiment', 'action_items', 'confidence_score'];
function validateGeminiShape(g) {
  const missing = [];
  for (let i = 0; i < REQUIRED.length; i++) {
    if (g[REQUIRED[i]] === undefined) missing.push(REQUIRED[i]);
  }
  if (!g.incident_type && !g.classification) missing.push('incident_type|classification');
  if (!Array.isArray(g.action_items)) missing.push('action_items(array)');
  if (missing.length) throw new Error('Gemini JSON missing required fields: ' + missing.join(', '));
}
const prev = $('Build extraction prompt').first().json;
const resp = $input.first().json;
let txt = resp.candidates?.[0]?.content?.parts?.[0]?.text;
if (!txt) throw new Error('Gemini returned no text');
txt = String(txt).trim();
if (txt.indexOf(FENCE) !== -1) {
  txt = txt.split(FENCE).join('');
  if (txt.toLowerCase().indexOf('json') === 0) txt = txt.slice(4);
  txt = txt.trim();
}
let g; try { g = JSON.parse(txt); } catch(e){ throw new Error('Bad JSON from Gemini: '+txt.slice(0,200)); }
validateGeminiShape(g);
g.filename = prev.filename;
g.correlation_id = prev.correlation_id;
return [{ json: g }];

function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
function actionsCsv(a){if(!a||!a.length)return'';return a.map(x=>{const o=(x&&x.owner&&String(x.owner).trim())?String(x.owner):'UNOWNED';const p=(x&&x.priority)?String(x.priority):'-';return p+': '+String(x.action||'')+' ('+o+')';}).join('; ');}
function fileType(n){const m=String(n||'').match(/\.([^.]+)$/);return m?m[1].toLowerCase():'txt';}
const g=$('Parse Gemini JSON').first().json;
const e=$input.first().json;
const classification=String(e.incident_type||g.incident_type||'other');
const filename=String(e.source_filename||g.filename||g.source_filename||'unknown');
const sentiment=String(g.sentiment||'neutral');
const routingTag=String(e.routing_tag||'auto-approved');
const summary=String(g.summary||'').slice(0,500);
const actionItems=actionsCsv(g.action_items||[]);
const row={document_id:e.document_id,filename:filename,file_type:fileType(filename),processed_at:e.processed_at,classification:classification,department:e.department,sentiment:sentiment,confidence_score:e.confidence_score,summary:summary,routing_tag:routingTag,sensitivity:e.sensitivity,action_items:actionItems,cvss_score:e.cvss_score,cve_ids:(e.cve_ids||[]).join(', ')};
const emailHtml='<h2>Document Processed</h2><p><b>File:</b> '+esc(filename)+'</p>+'<p><b>Classification:</b> '+esc(classification)+'</p><p><b>Sentiment:</b> '+esc(sentiment)+'</p>+'<p><b>Department:</b> '+esc(e.department)+'</p><p><b>Sensitivity:</b> '+esc(e.sensitivity)+'</p>+'<p><b>Routing tag:</b> '+esc(routingTag)+'</p><h3>Summary</h3><p>'+esc(summary)+'</p>+'<h3>Action items</h3><p>'+esc(actionItems||'(none)')+'</p>';const subjDigest='['+classification+'] New document processed: '+filename;
const subjSev1='[CONFIDENTIAL ESCALATE] '+filename+' - '+e.department;
const isSev1=e.computed_severity==='SEV1';
return [{json:{row,markdown:'# '+e.computed_severity+' - '+classification,is_sev1:isSev1,e,g,emailSubjectDigest:subjDigest,emailHtmlDigest:emailHtml,emailSubjectSev1:subjSev1,emailHtmlSev1:emailHtml,out_path:`/data/output_docs/${e.document_id}.md`}}];

const j = $('Compose record + outputs').first().json;
const buff = Buffer.from(j.markdown, 'utf8');
return [{ json: { out_path: j.out_path },
  binary: { data: { data: buff.toString('base64'),
    mimeType: 'text/markdown', fileName: j.document_id + '.md' } } }];
